+/**
+ * Audit logging service — records every notification dispatched through
+ * the priority router.
+ *
+ * Wraps PriorityRouter to intercept and log all route() calls without
+ * modifying the router itself.
+ *
+ * Depends on:
+ * - PriorityRouter (for actual routing)
+ */
+
+import type { PriorityRouter, PriorityNotification } from './priority-router.js';
+
+export interface AuditEntry {
+  id: string;
+  channel: 'sms' | 'email' | 'webhook';
+  priority: PriorityNotification['priority'];
+  recipient: string;
+  subject: string;
+  timestamp: Date;
+}
+
+let nextId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextId = 1;
+}
+
+export class AuditService {
+  private entries: AuditEntry[] = [];
+
+  constructor(private router: PriorityRouter) {}
+
+  /**
+   * Route a notification through the priority router and record an audit entry.
+   */
+  routeAndLog(notification: PriorityNotification): void {
+    const channel = this.resolveChannel(notification.priority);
+
+    this.router.route(notification);
+
+    const entry: AuditEntry = {
+      id: generateAuditId(),
+      channel,
+      priority: notification.priority,
+      recipient: notification.recipient,
+      subject: notification.subject,
+      timestamp: new Date(),
+    };
+    this.entries.push(entry);
+  }
+
+  private resolveChannel(priority: PriorityNotification['priority']): AuditEntry['channel'] {
+    switch (priority) {
+      case 'urgent':
+        return 'sms';
+      case 'normal':
+        return 'email';
+      case 'low':
+        return 'webhook';
+    }
+  }
+
+  getEntries(): AuditEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesForRecipient(recipient: string): AuditEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  getEntriesByChannel(channel: AuditEntry['channel']): AuditEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  clearEntries(): void {
+    this.entries = [];
+  }
