/**
 * Audit logging service — records every notification dispatched through
 * the priority router.
 *
 * Wraps PriorityRouter to intercept and log all route() calls without
 * modifying the router itself.
 *
 * Depends on:
 * - PriorityRouter (for actual routing)
 */

import type { PriorityRouter, PriorityNotification } from './priority-router.js';

export interface AuditEntry {
  id: string;
  channel: 'sms' | 'email' | 'webhook';
  priority: PriorityNotification['priority'];
  recipient: string;
  subject: string;
  timestamp: Date;
}

let nextId = 1;

function generateAuditId(): string {
  return `audit-${String(nextId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  constructor(private router: PriorityRouter) {}

  /**
   * Route a notification through the priority router and record an audit entry.
   */
  routeAndLog(notification: PriorityNotification): void {
    const channel = this.resolveChannel(notification.priority);

    this.router.route(notification);

    const entry: AuditEntry = {
      id: generateAuditId(),
      channel,
      priority: notification.priority,
      recipient: notification.recipient,
      subject: notification.subject,
      timestamp: new Date(),
    };
    this.entries.push(entry);
  }

  private resolveChannel(priority: PriorityNotification['priority']): AuditEntry['channel'] {
    switch (priority) {
      case 'urgent':
        return 'sms';
      case 'normal':
        return 'email';
      case 'low':
        return 'webhook';
    }
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: AuditEntry['channel']): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clearEntries(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — stores per-user channel preferences
 * that override priority-based routing.
 *
 * When a user has a channel preference set, notifications are re-routed
 * to their preferred channel regardless of the notification's priority level.
 *
 * Depends on:
 * - AuditService (for dispatching with audit logging)
 */

import type { AuditService } from './audit.service.js';
import type { PriorityNotification, Priority } from './priority-router.js';

export type Channel = 'sms' | 'email' | 'webhook';

export interface UserPreference {
  userId: string;
  channel: Channel;
}

export class NotificationPreferencesService {
  private preferences: Map<string, Channel> = new Map();

  constructor(private auditService: AuditService) {}

  /**
   * Set a user's preferred notification channel.
   */
  setPreference(userId: string, channel: Channel): void {
    this.preferences.set(userId, channel);
  }

  /**
   * Remove a user's channel preference (fall back to priority routing).
   */
  removePreference(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Get a user's preferred channel, if set.
   */
  getPreference(userId: string): Channel | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Send a notification, applying user preference override if one exists.
   *
   * If the user has a channel preference, the notification's priority is
   * remapped so the PriorityRouter delivers to the preferred channel.
   */
  send(notification: PriorityNotification): void {
    const userChannel = this.preferences.get(notification.recipient);

    if (userChannel) {
      const overridden: PriorityNotification = {
        ...notification,
        priority: this.channelToPriority(userChannel),
      };
      this.auditService.routeAndLog(overridden);
    } else {
      this.auditService.routeAndLog(notification);
    }
  }

  private channelToPriority(channel: Channel): Priority {
    switch (channel) {
      case 'sms':
        return 'urgent';
      case 'email':
        return 'normal';
      case 'webhook':
        return 'low';
    }
  }

  /**
   * Clear all preferences (useful for testing).
   */
  clearPreferences(): void {
    this.preferences.clear();
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
