  describe('user preferences override priority routing', () => {
    it('should override urgent→SMS to email when user prefers email', () => {
      preferences.setPreference('user-1', 'email');

      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Alert',
        body: 'Something urgent happened',
