      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
    });

    it('should override low→webhook to SMS when user prefers SMS', () => {
      preferences.setPreference('system', 'sms');

      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'system',
        subject: 'Report',
        body: 'Report ready',
      };

      preferences.send(notification);

      expect(smsChannel.getMessageCount()).toBe(1);
      expect(webhookChannel.getDeliveryCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
    });

    it('should use default priority routing when no preference is set', () => {
      const notification: PriorityNotification = {
        priority: 'normal',
        recipient: 'bob@example.com',
        subject: 'Hello',
        body: 'Test message',
      };

      preferences.send(notification);

      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(0);
    });

    it('should fall back to priority routing after preference is removed', () => {
      preferences.setPreference('user-1', 'webhook');
      preferences.removePreference('user-1');

      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Alert',
        body: 'Urgent alert',
      };

      preferences.send(notification);

      // Should route to SMS (urgent default), not webhook
      expect(smsChannel.getMessageCount()).toBe(1);
      expect(webhookChannel.getDeliveryCount()).toBe(0);
    });
  });

  describe('audit log tracks multiple dispatches', () => {
    it('should record all dispatches across priorities', () => {
      audit.routeAndLog({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Alert 1',
        body: 'Urgent',
      });
      audit.routeAndLog({
        priority: 'normal',
        recipient: 'user-2',
        subject: 'Info 1',
        body: 'Normal',
      });
      audit.routeAndLog({
        priority: 'low',
        recipient: 'system',
        subject: 'Log 1',
        body: 'Low',
      });

      expect(audit.getEntryCount()).toBe(3);
      expect(audit.getEntriesByChannel('sms')).toHaveLength(1);
      expect(audit.getEntriesByChannel('email')).toHaveLength(1);
      expect(audit.getEntriesByChannel('webhook')).toHaveLength(1);
    });

    it('should filter audit entries by recipient', () => {
      audit.routeAndLog({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'A',
        body: 'a',
      });
      audit.routeAndLog({
        priority: 'normal',
        recipient: 'user-1',
        subject: 'B',
        body: 'b',
      });
      audit.routeAndLog({
        priority: 'normal',
        recipient: 'user-2',
        subject: 'C',
        body: 'c',
      });

      expect(audit.getEntriesForRecipient('user-1')).toHaveLength(2);
      expect(audit.getEntriesForRecipient('user-2')).toHaveLength(1);
    });

    it('should generate sequential audit IDs', () => {
      audit.routeAndLog({
        priority: 'normal',
        recipient: 'user-1',
        subject: 'A',
        body: 'a',
      });
      audit.routeAndLog({
        priority: 'normal',
        recipient: 'user-2',
        subject: 'B',
        body: 'b',
      });

      const entries = audit.getEntries();
      expect(entries[0]?.id).toBe('audit-0001');
      expect(entries[1]?.id).toBe('audit-0002');
    });
  });
